type Market struct {
	// PDA bump
	Bump uint8 `json:"bump"`

	// Number of decimals used for the base token.
	//
	// Used to convert the oracle's price into a native/native price.
	BaseDecimals    uint8              `json:"baseDecimals"`
	QuoteDecimals   uint8              `json:"quoteDecimals"`
	Padding1        [5]uint8           `json:"padding1"`
	MarketAuthority solanago.PublicKey `json:"marketAuthority"`

	// No expiry = 0. Market will expire and no trading allowed after time_expiry
	TimeExpiry int64 `json:"timeExpiry"`

	// Admin who can collect fees from the market
	CollectFeeAdmin solanago.PublicKey `json:"collectFeeAdmin"`

	// Admin who must sign off on all order creations
	OpenOrdersAdmin NonZeroPubkeyOption `json:"openOrdersAdmin"`

	// Admin who must sign off on all event consumptions
	ConsumeEventsAdmin NonZeroPubkeyOption `json:"consumeEventsAdmin"`

	// Admin who can set market expired, prune orders and close the market
	CloseMarketAdmin NonZeroPubkeyOption `json:"closeMarketAdmin"`

	// Name. Trailing zero bytes are ignored.
	Name [16]uint8 `json:"name"`

	// Address of the BookSide account for bids
	Bids solanago.PublicKey `json:"bids"`

	// Address of the BookSide account for asks
	Asks solanago.PublicKey `json:"asks"`

	// Address of the EventHeap account
	EventHeap solanago.PublicKey `json:"eventHeap"`

	// Oracles account address
	OracleA NonZeroPubkeyOption `json:"oracleA"`
	OracleB NonZeroPubkeyOption `json:"oracleB"`

	// Oracle configuration
	OracleConfig OracleConfig `json:"oracleConfig"`

	// Number of quote native in a quote lot. Must be a power of 10.
	//
	// Primarily useful for increasing the tick size on the market: A lot price
	// of 1 becomes a native price of quote_lot_size/base_lot_size becomes a
	// ui price of quote_lot_size*base_decimals/base_lot_size/quote_decimals.
	QuoteLotSize int64 `json:"quoteLotSize"`

	// Number of base native in a base lot. Must be a power of 10.
	//
	// Example: If base decimals for the underlying asset is 6, base lot size
	// is 100 and and base position lots is 10_000 then base position native is
	// 1_000_000 and base position ui is 1.
	BaseLotSize int64 `json:"baseLotSize"`

	// Total number of orders seen
	SeqNum uint64 `json:"seqNum"`

	// Timestamp in seconds that the market was registered at.
	RegistrationTime int64 `json:"registrationTime"`

	// Fees
	//
	// Fee (in 10^-6) when matching maker orders.
	// maker_fee < 0 it means some of the taker_fees goes to the maker
	// maker_fee > 0, it means no taker_fee to the maker, and maker fee goes to the referral
	MakerFee int64 `json:"makerFee"`

	// Fee (in 10^-6) for taker orders, always >= 0.
	TakerFee int64 `json:"takerFee"`

	// Total fees accrued in native quote
	FeesAccrued binary.Uint128 `json:"feesAccrued"`

	// Total fees settled in native quote
	FeesToReferrers binary.Uint128 `json:"feesToReferrers"`

	// Referrer rebates to be distributed
	ReferrerRebatesAccrued uint64 `json:"referrerRebatesAccrued"`

	// Fees generated and available to withdraw via sweep_fees
	FeesAvailable uint64 `json:"feesAvailable"`

	// Cumulative maker volume (same as taker volume) in quote native units
	MakerVolume binary.Uint128 `json:"makerVolume"`

	// Cumulative taker volume in quote native units due to place take orders
	TakerVolumeWoOo   binary.Uint128     `json:"takerVolumeWoOo"`
	BaseMint          solanago.PublicKey `json:"baseMint"`
	QuoteMint         solanago.PublicKey `json:"quoteMint"`
	MarketBaseVault   solanago.PublicKey `json:"marketBaseVault"`
	BaseDepositTotal  uint64             `json:"baseDepositTotal"`
	MarketQuoteVault  solanago.PublicKey `json:"marketQuoteVault"`
	QuoteDepositTotal uint64             `json:"quoteDepositTotal"`
	Reserved          [128]uint8         `json:"reserved"`
}

